  const t={};seats.forEach(c=>t[c.party]=(t[c.party]||0)+1);
  const pl=Object.entries(t).map(([p,n])=>`<span class="pill ${pm(p).cls}" style="font-size:8px;padding:1px 5px">${p} ${n}</span>`).join('');
