// ────────────────── GRIEVANCES ──────────────────
const GK='nagrik_grievances_v3';
const BACKEND_URL='';

const getJWT=()=>localStorage.getItem('nagrik_jwt');
const authHeaders=()=>({'Content-Type':'application/json','Authorization':`Bearer ${getJWT()}`});

function transformGriev(g){
  return {
    id: g.id,
    ts: g.created_at,
    category: g.category,
    description: g.description,
    photo: g.photo_url,
    location: g.location_text,
    gps: (g.gps_lat && g.gps_lng) ? { lat: parseFloat(g.gps_lat), lng: parseFloat(g.gps_lng) } : null,
    representative: (g.rep_type && g.rep_id) ? `${g.rep_type}-${g.rep_id}` : null,
    isPublic: g.is_public,
    refCode: g.ref_code,
    status: g.status,
    upvotes: g.upvotes || 0,
    submitterName: g.submitter_name || null,
  };
}

async function getGrievs(){
  try{
    const jwt=getJWT();
    if(!jwt)return[];
    const res=await fetch(`${BACKEND_URL}/api/grievances/mine`,{headers:authHeaders()});
    if(!res.ok)return[];
    const data=await res.json();
    return (data.data || []).map(transformGriev);
  }catch(e){console.warn('Fetch grievances failed',e);return[];}
}

async function saveGrievs(grievanceData){
  try{
    const jwt=getJWT();
    if(!jwt){toast('Log in first','err');return false;}
    const res=await fetch(`${BACKEND_URL}/api/grievances`,{method:'POST',headers:authHeaders(),body:JSON.stringify(grievanceData)});
    if(!res.ok){
      if(res.status===401){toast('Session expired','err');setTimeout(()=>{window.location.href='/login';},1500);return false;}
      const err=await res.json();toast(err.error||'Failed to submit','err');return false;
    }
    const result=await res.json();
    toast(`Filed: ${result.refCode}`,'success');
    return true;
  }catch(e){console.error('Save error',e);toast('Network error','err');return false;}
}

function openGrievModal(repType,repId,wardNo,jumpToEmail){
  repType=repType||''; repId=repId||''; wardNo=wardNo||'';
  // Pre-fetch location silently (fixes iOS geolocation-inside-callback issue)
  if(navigator.geolocation&&!S.userLoc){
    navigator.geolocation.getCurrentPosition(
      pos=>{S.userLoc={lat:pos.coords.latitude,lng:pos.coords.longitude,accuracy:pos.coords.accuracy};},
      ()=>{},
      {enableHighAccuracy:false,timeout:8000,maximumAge:60000}
    );
  }
  // Auto-fill location
  if(S.userLoc&&!document.getElementById('g-loc').value){
    const w=pipWard(S.userLoc.lat,S.userLoc.lng);
    document.getElementById('g-loc').value=w?`Ward ${w.wno} · ${w.name}`:`${S.userLoc.lat.toFixed(5)}, ${S.userLoc.lng.toFixed(5)}`;
  }
  // Set rep
  const repSel=document.getElementById('g-rep');
  if(repSel){
    if(repType==='corp'&&repId) repSel.value='corp-'+repId;
    else if(repType==='mla'&&repId) repSel.value='mla-'+repId;
    else if(repType==='mp'&&repId) repSel.value='mp-'+repId;
    else if(repType==='ward'&&wardNo){
      const seat=CORPS.find(c=>String(c.ward_no)===String(wardNo));
      if(seat) repSel.value='corp-'+seat.id;
    }
  }
  buildEmailDraft();
  document.getElementById('griev-modal').classList.add('open');
  lockScroll();
  if(jumpToEmail) setTimeout(()=>{toggleEmailPreview(true)},400);
}
function closeGrievModal(){
  document.getElementById('griev-modal').classList.remove('open');
  unlockScroll();
}

function buildRepSelector(){
  const sel=document.getElementById('g-rep');
  if(!sel) return;
  sel.innerHTML='<option value="">— Select (or auto-detect from map) —</option>';
  CORPS.forEach(c=>{
    sel.innerHTML+=`<option value="corp-${c.id}">[Corporator] ${c.name} · W${c.ward_no}-${c.seat}</option>`;
  });
  MLAS.forEach(m=>{
    sel.innerHTML+=`<option value="mla-${m.const}">[MLA] ${m.name} · ${m.const}</option>`;
  });
  MPS.forEach(m=>{
    sel.innerHTML+=`<option value="mp-${m.const}">[MP] ${m.name} · ${m.const}</option>`;
  });
}

// ────── EMAIL DRAFT ENGINE ──────
function getRepFromSel(){
  const v=document.getElementById('g-rep')?.value||'';
  if(!v) return null;
  if(v.startsWith('corp-')){const c=CORPS.find(x=>x.id===v.slice(5));return c?{type:'corp',obj:c,email:null,name:c.name}:null}
  if(v.startsWith('mla-')){const m=MLAS.find(x=>x.const===v.slice(4));return m?{type:'mla',obj:m,email:m.email||'',name:m.name}:null}
  if(v.startsWith('mp-')){const p=MPS.find(x=>x.const===v.slice(3));return p?{type:'mp',obj:p,email:p.email||'',name:p.name}:null}
  return null;
}

function buildEmailDraft(){
  const cat=document.getElementById('g-cat')?.value||'Other';
  const desc=(document.getElementById('g-desc')?.value||'').trim();
  const loc=document.getElementById('g-loc')?.value||'[Location not specified]';
  const rep=getRepFromSel();
  const admin=ADMIN_EMAILS[cat]||ADMIN_EMAILS['Other'];
  const today=new Date().toLocaleDateString('en-IN',{day:'numeric',month:'long',year:'numeric'});
  const gps=S.photoGPS||S.userLoc;

  let toName='Sir/Madam';
  if(rep){
    if(rep.type==='corp') toName=`${rep.obj.name} Ji (Corporator, Ward ${rep.obj.ward_no}, Seat ${rep.obj.seat})`;
    else if(rep.type==='mla') toName=`${rep.obj.name} Ji (MLA, ${rep.obj.const})`;
    else if(rep.type==='mp') toName=`${rep.obj.name} Ji (MP, ${rep.obj.const} Lok Sabha)`;
  }

  const draft=`Subject: Urgent Civic Grievance — ${cat} · ${loc}

Date: ${today}
To: ${toName}
CC: ${admin.name}${gps?`\nLocation (GPS): https://maps.google.com/?q=${gps.lat.toFixed(5)},${gps.lng.toFixed(5)}`:''}

Respected ${toName},

I am writing to bring to your urgent attention a serious civic issue in ${loc} that requires immediate action.

Issue Category: ${cat}
${desc?`\nDetailed Description:\n${desc}`:'[Please describe the issue in detail]'}

${gps?`The exact GPS coordinates of the issue are: Lat ${gps.lat.toFixed(5)}, Lng ${gps.lng.toFixed(5)}.
Google Maps link: https://maps.google.com/?q=${gps.lat.toFixed(5)},${gps.lng.toFixed(5)}`:''}

As a citizen of Pune, I urge you to:
1. Acknowledge receipt of this complaint within 48 hours
2. Initiate inspection within 72 hours
3. Provide resolution timeline as per PMC Service Level Agreement

Please note that under the Right to Information Act, 2005 and PMC Service Charter, citizens are entitled to timely grievance redressal. Non-response attracts penalties under RTI Section 20.

📎 ATTACHMENT: Please attach the geotagged photo from your camera roll to this email before sending.

Awaiting prompt action,
A Concerned Citizen of Pune
Filed via: Nagrik OS (nagrik-os.pune.in)
© Krishant Dutta`;

  const preview=document.getElementById('email-preview');
  const actions=document.getElementById('email-actions');
  if(preview) preview.textContent=draft;
  window.__emailDraft=draft;
  window.__repObj=rep;
  window.__adminObj=admin;
  return draft;
}

function toggleEmailPreview(forceOpen){
  const preview=document.getElementById('email-preview');
  const actions=document.getElementById('email-actions');
  const btn=document.getElementById('email-toggle-btn');
  if(!preview) return;
  S.emailPreviewOpen=forceOpen!==undefined?forceOpen:!S.emailPreviewOpen;
  preview.classList.toggle('shown',S.emailPreviewOpen);
  if(actions) actions.style.display=S.emailPreviewOpen?'flex':'none';
  if(btn) btn.textContent=S.emailPreviewOpen?'HIDE':'SHOW';
}

function copyEmailText(){
  const d=window.__emailDraft||buildEmailDraft();
  navigator.clipboard.writeText(d).then(
    ()=>toast('Email text copied — paste into your mail app'),
    ()=>{
      // Fallback
      const ta=document.createElement('textarea');
      ta.value=d;document.body.appendChild(ta);ta.select();
      try{document.execCommand('copy');toast('Copied!')}catch(e){toast('Copy failed','err')}
      document.body.removeChild(ta);
    }
  );
}

function openEmailClient(target){
  const d=window.__emailDraft||buildEmailDraft();
  const rep=window.__repObj;
  const admin=window.__adminObj||ADMIN_EMAILS['Other'];
  const cat=document.getElementById('g-cat')?.value||'Other';
  const loc=document.getElementById('g-loc')?.value||'';
  const subj=encodeURIComponent(`Urgent Civic Grievance — ${cat} · ${loc}`);
  const body=encodeURIComponent(d);
  const adminCC=admin.cc?`&cc=${encodeURIComponent(admin.cc)}`:'';
  const adminEmail=encodeURIComponent(admin.email);
  let mailto='';
  if(target==='corp'&&rep?.type==='corp'){
    // To: corporator ward email, CC: admin dept
    mailto=`mailto:ward${rep.obj.ward_no}@${CITY_CONFIG.pmcDomain}?subject=${subj}&cc=${adminEmail}&body=${body}`;
  } else if(target==='admin'){
    // To: admin dept, CC: commissioner
    mailto=`mailto:${admin.email}?subject=${subj}${adminCC}&body=${body}`;
  } else if(target==='mla'&&rep?.type==='mla'&&rep.obj.email){
    mailto=`mailto:${rep.obj.email}?subject=${subj}&cc=${adminEmail}&body=${body}`;
  } else if(target==='mp'&&rep?.type==='mp'&&rep.obj.email){
    mailto=`mailto:${rep.obj.email}?subject=${subj}&cc=${adminEmail}&body=${body}`;
  } else {
    copyEmailText();
    toast('No email registered — text copied. Attach photo & send from your mail app.','warn');
    return;
  }
  window.location.href=mailto;
}

// ────── PHOTO HANDLING ──────
function handlePhoto(ev){
  const file=ev.target.files[0];
  if(!file) return;
  if(file.size>6*1024*1024){toast('Photo too large (max 6MB)','err');return}
  const reader=new FileReader();
  reader.onload=e=>{
    S.photoData=e.target.result;
    document.getElementById('photo-img').src=S.photoData;
    document.getElementById('photo-zone').style.display='none';
    document.getElementById('photo-prev').classList.add('shown');
    // Get GPS — use cached location if available (avoids iOS gesture-restriction)
    function applyGPS(lat,lng,accuracy){
      S.photoGPS={lat,lng,accuracy};
      const w=pipWard(lat,lng);
      const meta=document.getElementById('geotag-meta');
      const txt=document.getElementById('geotag-txt');
      if(meta){meta.classList.add('shown');meta.classList.remove('warn')}
      if(txt) txt.textContent=`Geotagged · ${lat.toFixed(5)}, ${lng.toFixed(5)} · ±${Math.round(accuracy)}m${w?' · Ward '+w.wno:''}`;
      if(w&&!document.getElementById('g-loc').value) document.getElementById('g-loc').value=`Ward ${w.wno} · ${w.name} (geotagged)`;
      buildEmailDraft();
    }
    if(S.userLoc){
      applyGPS(S.userLoc.lat,S.userLoc.lng,S.userLoc.accuracy);
    } else if(navigator.geolocation){
      navigator.geolocation.getCurrentPosition(
        pos=>applyGPS(pos.coords.latitude,pos.coords.longitude,pos.coords.accuracy),
        ()=>{
          // Try low-accuracy
          navigator.geolocation.getCurrentPosition(
            pos=>applyGPS(pos.coords.latitude,pos.coords.longitude,pos.coords.accuracy),
            ()=>{
              const meta=document.getElementById('geotag-meta');
              if(meta){meta.classList.add('shown','warn')}
              const txt=document.getElementById('geotag-txt');
              if(txt) txt.textContent='Geotag failed — go to Settings → Privacy → Location → allow this site';
            },
            {enableHighAccuracy:false,timeout:8000,maximumAge:60000}
          );
        },
        {enableHighAccuracy:true,timeout:8000,maximumAge:0}
      );
    }
  };
  reader.readAsDataURL(file);
}
function removePhoto(){
  S.photoData=null;S.photoGPS=null;
  document.getElementById('g-photo').value='';
  document.getElementById('photo-prev').classList.remove('shown');
  document.getElementById('photo-zone').style.display='block';
  const meta=document.getElementById('geotag-meta');
  if(meta){meta.classList.remove('shown','warn')}
}

