async function submitGrievance(){
  const desc=(document.getElementById('g-desc')?.value||'').trim();
  if(!desc){toast('Please describe the grievance','err');return}
  const isPublic = document.getElementById('g-public')?.checked || false;
  const g={
    id:'g-'+Date.now()+'-'+Math.random().toString(36).slice(2,6),
    ts:new Date().toISOString(),
    category:document.getElementById('g-cat')?.value||'Other',
    description:desc,
    location:document.getElementById('g-loc')?.value||'—',
    gps:S.photoGPS||S.userLoc||null,
    representative:document.getElementById('g-rep')?.value||null,
    photo:S.photoData||null,
    isPublic,
    emailDraft:window.__emailDraft||null,
  };
const success = await saveGrievs(g);
if(!success) return; // Exit if submission failed

  // Reset form
  document.getElementById('g-desc').value='';
  document.getElementById('g-loc').value='';
  document.getElementById('g-rep').value='';
  if(document.getElementById('g-public')) document.getElementById('g-public').checked=false;
  removePhoto();
  S.emailPreviewOpen=false;
  toggleEmailPreview(false);
  closeGrievModal();
  updateGrievBadge();
  if(S.page==='grievance') await renderGrievances();
  toast(`Grievance logged${isPublic?' and shared to public feed':''}. View under Grievances tab.`);
}

