function switchGTab(t){
  S.grievanceTab=t;
  document.getElementById('gtab-my').classList.toggle('active',t==='my');
  document.getElementById('gtab-pub').classList.toggle('active',t==='pub');
  document.getElementById('griev-my').style.display=t==='my'?'grid':'none';
  document.getElementById('griev-pub').style.display=t==='pub'?'grid':'none';
  if(t==='pub') renderPublicFeed();
}

async function renderGrievances(){
  renderMyGrievances();
  if(S.grievanceTab==='pub') renderPublicFeed();
}

async function renderMyGrievances(){
  const list = await getGrievs();
  const feed=document.getElementById('griev-my');
  if(!feed) return;
  if(!list.length){feed.innerHTML='<div class="griev-card empty">No grievances yet. Tap "New Grievance" to file one with photo + geotag.</div>';return}
  feed.innerHTML=list.map(g=>grievCard(g,true)).join('');
}

async function renderPublicFeed(){
  const feed = document.getElementById('griev-pub');
  if(!feed) return;
  
  try{
    // HARDCODED to 'pune' - bypasses CITY_CONFIG.id undefined bug
    const url = `${BACKEND_URL}/api/grievances/public?cityId=pune`;
    console.log('[Public Feed] Fetching:', url);
    
    const res = await fetch(url);
    console.log('[Public Feed] Response status:', res.status);
    
    if(!res.ok){ 
      feed.innerHTML = '<div class="griev-card empty">Failed to load public feed (HTTP ' + res.status + ')</div>';
      return;
    }
    
    const data = await res.json();
    console.log('[Public Feed] Got', data.data?.length || 0, 'grievances');
    console.log('[Public Feed] Sample:', data.data?.[0]);
    
    const list = (data.data || []).map(transformGriev);
    
    if(!list.length){
      feed.innerHTML = '<div class="griev-card empty">No public geotagged grievances yet. Submit one with photo + location and tick "Share to Public Feed".</div>';
      return;
    }
    
    feed.innerHTML = list.map(g => grievCard(g, false)).join('');
    console.log('[Public Feed] ✅ Rendered', list.length, 'cards');
  }catch(e){
    console.error('[Public Feed] Error:', e);
    feed.innerHTML = '<div class="griev-card empty">Network error: ' + e.message + '</div>';
  }
}

function grievCard(g,isOwn){
  const date=new Date(g.ts).toLocaleString('en-IN',{dateStyle:'medium',timeStyle:'short'});
  let repHTML='';
  if(g.representative){
    if(g.representative.startsWith('corp-')){const c=CORPS.find(x=>x.id===g.representative.slice(5));if(c) repHTML=`<span>👤 ${esc(c.name)} · W${c.ward_no}-${c.seat}</span>`}
    else if(g.representative.startsWith('mla-')){const m=MLAS.find(x=>x.const===g.representative.slice(4));if(m) repHTML=`<span>🏛 MLA ${esc(m.name)}</span>`}
    else if(g.representative.startsWith('mp-')){const p=MPS.find(x=>x.const===g.representative.slice(3));if(p) repHTML=`<span>🇮🇳 MP ${esc(p.name)}</span>`}
  }
  const admin=ADMIN_EMAILS[g.category]||ADMIN_EMAILS['Other'];
  return `<div class="griev-card">
    ${g.photo?`<img src="${g.photo}" class="griev-photo" alt="Evidence photo" loading="lazy">`:''}
    <div class="griev-body">
      <div class="griev-hrow">
        <span class="griev-cat">${esc(g.category)}</span>
        <span class="griev-time">${date}</span>
      </div>
      <div class="griev-txt">${esc(g.description)}</div>
      <div class="griev-meta">
        ${g.location&&g.location!=='—'?`<span>📍 ${esc(g.location)}</span>`:''}
        ${g.gps?`<span>🛰 <a href="https://maps.google.com/?q=${g.gps.lat.toFixed(5)},${g.gps.lng.toFixed(5)}" target="_blank" rel="noopener" style="color:var(--mint)">View on Maps</a></span>`:''}
        ${repHTML}
        ${g.isPublic?'<span style="color:var(--mint);font-size:9px">PUBLIC</span>':''}
      </div>
      <div class="griev-actions">
        ${isOwn?`<button class="g-del" onclick="delGriev('${g.id}')">Delete</button>`:''}
        <button class="g-share" onclick="copyGriev('${g.id}')">Copy Text</button>
        <button class="g-email" onclick="emailGriev('${g.id}','admin')">✉ Email PMC</button>
        ${g.representative&&g.representative.startsWith('mla-')?`<button class="g-email" onclick="emailGriev('${g.id}','mla')">✉ Email MLA</button>`:''}
        ${g.representative&&g.representative.startsWith('mp-')?`<button class="g-email" onclick="emailGriev('${g.id}','mp')">✉ Email MP</button>`:''}
        ${g.gps?`<a class="g-share" href="https://maps.google.com/?q=${g.gps.lat.toFixed(5)},${g.gps.lng.toFixed(5)}" target="_blank" rel="noopener">📍 Maps</a>`:''}
      </div>
    </div>
  </div>`;
}

async function delGriev(id){
  if(!confirm('Delete this grievance permanently?')) return;
  try {
    const res = await fetch(`${BACKEND_URL}/api/grievances/${id}`, {
      method: 'DELETE',
      headers: authHeaders()
    });
    if (!res.ok) {
      if (res.status === 401) { toast('Session expired','err'); setTimeout(()=>{window.location.href='/login';},1500); return; }
      const err = await res.json();
      toast(err.error || 'Delete failed','err');
      return;
    }
    await renderGrievances();
    updateGrievBadge();
    toast('Deleted','success');
  } catch (e) {
    console.error('Delete error:', e);
    toast('Network error','err');
  }
}

async function copyGriev(id){
  const list = await getGrievs();
  const g = list.find(x => x.id === id);
  if (!g) { toast('Grievance not found','err'); return; }
  
  const admin = (typeof ADMIN_EMAILS !== 'undefined' && ADMIN_EMAILS[g.category]) || (typeof ADMIN_EMAILS !== 'undefined' && ADMIN_EMAILS['Other']) || 'grievances@pmc.gov.in';
  const date = new Date(g.ts).toLocaleString('en-IN', {dateStyle: 'medium', timeStyle: 'short'});
  
  const txt = `NAGRIK OS · Civic Grievance Report
─────────────────────────────────
Reference: ${g.refCode || g.id}
Filed: ${date}
Category: ${g.category}
Status: ${g.status || 'filed'}

Description:
${g.description}

${g.location ? `Location: ${g.location}` : ''}
${g.gps ? `GPS: ${g.gps.lat.toFixed(5)}, ${g.gps.lng.toFixed(5)}` : ''}
${g.gps ? `Maps: https://maps.google.com/?q=${g.gps.lat.toFixed(5)},${g.gps.lng.toFixed(5)}` : ''}

Filed via Nagrik OS · Citizen Accountability Platform
${admin ? `→ Send to: ${admin}` : ''}`.trim();

  try {
    await navigator.clipboard.writeText(txt);
    toast('Copied to clipboard','success');
  } catch (e) {
    // Fallback for browsers without clipboard API
    const ta = document.createElement('textarea');
    ta.value = txt;
    document.body.appendChild(ta);
    ta.select();
    document.execCommand('copy');
    document.body.removeChild(ta);
    toast('Copied to clipboard','success');
  }
}

async function emailGriev(id, target){
  const list = await getGrievs();
  const g = list.find(x => x.id === id);
  if (!g) { toast('Grievance not found','err'); return; }
  
  let to = '';
  if (target === 'admin') {
    to = (typeof ADMIN_EMAILS !== 'undefined' && ADMIN_EMAILS[g.category]) || (typeof ADMIN_EMAILS !== 'undefined' && ADMIN_EMAILS['Other']) || 'grievances@pmc.gov.in';
  } else if (target === 'mla' && g.representative && g.representative.startsWith('mla-')) {
    const mlaId = g.representative.slice(4);
    const mla = (typeof MLAS !== 'undefined') ? MLAS.find(m => m.const === mlaId) : null;
    to = mla?.email || '';
  } else if (target === 'mp' && g.representative && g.representative.startsWith('mp-')) {
    const mpId = g.representative.slice(3);
    const mp = (typeof MPS !== 'undefined') ? MPS.find(p => p.const === mpId) : null;
    to = mp?.email || '';
  }
  
  if (!to) { toast(`No ${target.toUpperCase()} email found`,'err'); return; }
  
  const date = new Date(g.ts).toLocaleString('en-IN', {dateStyle: 'medium', timeStyle: 'short'});
  const subject = `Urgent Civic Grievance: ${g.category} — Ref ${g.refCode || g.id}`;
  
  const body = `Dear Sir/Madam,

I am writing to bring to your urgent attention the following civic grievance:

Reference Code: ${g.refCode || g.id}
Filed Date: ${date}
Category: ${g.category}

Description:
${g.description}

${g.location ? `Location: ${g.location}` : ''}
${g.gps ? `GPS Coordinates: ${g.gps.lat.toFixed(5)}, ${g.gps.lng.toFixed(5)}` : ''}
${g.gps ? `View on Map: https://maps.google.com/?q=${g.gps.lat.toFixed(5)},${g.gps.lng.toFixed(5)}` : ''}
${g.photo ? `Photo Evidence: ${g.photo}` : ''}

As per the Right to Information Act, 2005, and citizen accountability standards, I request:
1. Acknowledgment of this grievance within 7 days
2. Action taken within 30 days as per civic norms
3. A written response on the steps taken

I am filing this via Nagrik OS — a citizen accountability platform — and a public record is being maintained.

Thank you for your attention to this matter.

Regards,
A Concerned Citizen
Filed via Nagrik OS · सत्यमेव जयते`.trim();

  const mailtoUrl = `mailto:${encodeURIComponent(to)}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
  window.location.href = mailtoUrl;
}


function exportGrievances(){
  const list=getGrievs();
  if(!list.length){toast('No grievances to export','warn');return}
  const blob=new Blob([JSON.stringify(list,null,2)],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url;a.download=`nagrik-os-grievances-${new Date().toISOString().slice(0,10)}.json`;
  a.click();URL.revokeObjectURL(url);
  toast(`Exported ${list.length} grievance(s)`);
}

